```javascript
class MemoryManager {
  constructor(size) {
    this.size = size;
    this.memory = new Array(size).fill(0);
  }

  allocate(blockSize) {
    let start = this.memory.indexOf(0);
    if (start === -1 || start + blockSize > this.size) {
      throw new Error("Not enough memory");
    }
    this.memory.fill(1, start, start + blockSize);
    return start;
  }

  free(index, blockSize) {
    if (index + blockSize > this.size) {
      throw new Error("Invalid block size");
    }
    this.memory.fill(0, index, index + blockSize);
  }

  displayMemory() {
    return this.memory;
  }

  reallocate(index, currentSize, newSize) {
    if (newSize > currentSize) {
      // Expanding block
      let requiredSpace = newSize - currentSize;
      let availableSpace = this.memory.slice(index + currentSize, index + newSize).indexOf(1);
      if (availableSpace !== -1 && availableSpace < requiredSpace) {
        return false; // Not enough contiguous free space
      }
      this.memory.fill(1, index + currentSize, index + newSize);
    } else {
      // Shrinking block
      this.memory.fill(0, index + newSize, index + currentSize);
    }
    return true;
  }
}
