public class ConnectionManager implements IConnection {
    private boolean connected;
    private int timeoutMilliseconds;

    @Override
    public void connect() {
        connected = true;
        System.out.println("Connected successfully.");
        // A new connection resets the timeout countdown.
        if (timeoutMilliseconds > 0) {
            startTimeoutTimer();
        }
    }

    @Override
    public void disconnect() {
        connected = false;
        System.out.println("Disconnected successfully.");
    }

    @Override
    public boolean isConnected() {
        return connected;
    }

    public void setTimeout(int milliseconds) {
        timeoutMilliseconds = milliseconds;
        System.out.println("Timeout is set to " + milliseconds + " milliseconds.");
        // When a timeout value is set, start monitoring the connection status.
        if (connected) {
            startTimeoutTimer();
        }
    }

    private void startTimeoutTimer() {
        new Thread(() -> {
            try {
                Thread.sleep(timeoutMilliseconds);
                if (connected) {
                    System.out.println("Connection timeout exceeded.");
                    disconnect();
                }
            } catch (InterruptedException e) {
                System.out.println("Timeout handling interrupted.");
            }
        }).start();
    }
}
