trait Encryptor {
    fn encrypt(&self, data: &str) -> String;
    fn decrypt(&self, data: &str) -> String;
}

struct SimpleEncryptor {
    shift: u8,
}

impl Encryptor for SimpleEncryptor {
    fn encrypt(&self, data: &str) -> String {
        data.chars()
            .map(|c| {
                if c.is_ascii_alphabetic() {
                    let first = if c.is_ascii_lowercase() { 'a' } else { 'A' };
                    let offset = c as u8 - first as u8;
                    let shifted = (offset + self.shift) % 26;
                    (first as u8 + shifted) as char
                } else {
                    c
                }
            })
            .collect()
    }

    fn decrypt(&self, data: &str) -> String {
        data.chars()
            .map(|c| {
                if c.is_ascii_alphabetic() {
                    let first = if c.is_ascii_lowercase() { 'a' } else { 'A' };
                    let offset = c as u8 - first as u8;
                    let shifted = (offset + 26 - self.shift) % 26; // Adding 26 to handle negative shift
                    (first as u8 + shifted) as char
                } else {
                    c
                }
            })
            .collect()
    }
}

