void parse_json_data(char* data) {
    char* token;
    char* rest = data;

    while ((token = strtok_r(rest, ";", &rest))) {
        // Split each token further by ':' to distinguish keys and values
        char* inner_token;
        char* inner_rest = token;
        inner_token = strtok_r(inner_rest, ":", &inner_rest);
