use std::collections::{HashSet, HashMap, VecDeque};

struct Graph {
    edges: HashMap<i32, Vec<i32>>,
}

impl Graph {
    fn new() -> Self {
        Graph {
            edges: HashMap::new(),
        }
    }

    fn add_edge(&mut self, src: i32, dst: i32) {
        self.edges.entry(src).or_insert_with(Vec::new).push(dst);
    }

    fn get_neighbors(&self, node: i32) -> Vec<i32> {
        self.edges.get(&node).cloned().unwrap_or_else(Vec::new)
    }

    fn depth_first_search(&self, start: i32) -> Vec<i32> {
        let mut visited = HashSet::new();
        let mut stack = VecDeque::new();
        let mut order = Vec::new();

        stack.push_back(start);

        while let Some(node) = stack.pop_back() {
            if visited.insert(node) {
                order.push(node);
                if let Some(neighbors) = self.edges.get(&node) {
                    for &neighbor in neighbors.iter().rev() {
                        if !visited.contains(&neighbor) {
                            stack.push_back(neighbor);
                        }
                    }
                }
            }
        }

        order
    }

    fn complex_dfs_analysis(&self, start: i32) -> HashMap<String, usize> {
        let dfs_order = self.depth_first_search(start);
        let unique_count = dfs_order.iter().collect::<HashSet<_>>().len();
        let visit_count = dfs_order.len();

        [("visited_nodes", visit_count), ("unique_nodes", unique_count)]
            .iter()
            .map(|&(key, value)| (key.to_string(), value))
            .collect()
